const CONDITION=["精神飽滿","正常","疲勞","低潮"];
const CONDITION_EFFECT={"精神飽滿":1.06,"正常":1.0,"疲勞":0.90,"低潮":0.78};
const MOBA_WEIGHTS={reflex:1.0,accuracy:0.8,apm:1.2,positioning:1.1,mapAware:1.3,tacticalIQ:1.2,decision:1.1,adaptability:0.9,courage:1.0,clutch:0.8,focus:0.9,resilience:0.7,comms:1.0,leadership:0.8,synergy:1.1,learning:0.6};
const FPS_WEIGHTS={reflex:1.3,accuracy:1.4,apm:1.0,positioning:1.2,mapAware:1.1,tacticalIQ:1.0,decision:0.9,adaptability:0.8,courage:1.1,clutch:1.3,focus:1.0,resilience:0.8,comms:0.9,leadership:0.7,synergy:0.8,learning:0.5};
// ═══ 3D CS 對戰轉接層（EsportsFPS3D 對接）═══════════════════════════
// 長鍵(本遊戲) → 短鍵(3D 引擎)；依中文名一對一對應
const STAT_L2S={reflex:"rxn",accuracy:"acc",apm:"apm",positioning:"pos",mapAware:"vis",tacticalIQ:"tac",decision:"dec",adaptability:"adp",courage:"cou",clutch:"str",focus:"foc",resilience:"res",comms:"com",leadership:"led",synergy:"coo",learning:"lrn"};
const toShortStats=(stats={})=>{const o={};for(const k in STAT_L2S)o[STAT_L2S[k]]=stats[k]??50;return o;};
// MOBA 路線 → FPS 定位（與 3D 內建德國海豹陣容一致：上路=突破 中路=步槍 下路=狙擊 打野=游走 輔助=指揮）
const MOBA2FPS={"上路":"entry","打野":"lurker","中路":"rifler","下路":"awp","輔助":"igl"};
const FPS_ROLE_ZH={entry:"突破手",rifler:"步槍手",awp:"狙擊手",lurker:"游走手",igl:"指揮",support:"輔助"};
// 遊戲 FPS 戰術(f1–f8) → 3D 戰術類型(execute/rush/default)
const FPS_TACTIC_TYPE={f1:"default",f2:"rush",f3:"execute",f4:"default",f5:"execute",f6:"default",f7:"default",f8:"default"};
// FPS 綜合戰力（短鍵、FPS 權重）
const FPS_W_S={acc:1.4,rxn:1.3,str:1.3,pos:1.2,cou:1.1,vis:1.1,apm:1.0,tac:1.0,foc:1.0,dec:0.9,com:0.9,adp:0.8,res:0.8,coo:0.8,led:0.7,lrn:0.5};
const fpsOvr=(short)=>{let t=0,w=0;for(const k in FPS_W_S){t+=(short[k]??50)*FPS_W_S[k];w+=FPS_W_S[k];}return Math.round(t/w);};
// 把我方先發(本遊戲長鍵 + MOBA 角色)轉成 3D T 方名單；指派固定 id t1–t5
function toFpsRoster(starters){
  return starters.slice(0,5).map((p,i)=>{
    const short=toShortStats(p.stats);
    const role=MOBA2FPS[p.role]||["entry","rifler","awp","lurker","igl"][i]||"rifler";
    const ovr=fpsOvr(short);
    return{id:"t"+(i+1),name:p.name,side:"t",role,fpsRole:FPS_ROLE_ZH[role],
      moba:ovr,fps:ovr,sta:p.energy??82,personality:p.personality||"steady",
      morale:p.morale,condition:p.condition,stats:short,_gid:p.id};
  });
}
// 對手戰隊 Compulsary（CT 方，短鍵）— 與 3D 引擎內建對手一致
