// ── 碰撞檢測：點是否在牆內 ──
function inWall(p,walls){for(const w of walls){if(p.x>=w.x-1&&p.x<=w.x+w.w+1&&p.y>=w.y-1&&p.y<=w.y+w.h+1)return w;}return null;}
// ── 繞行：若目標踩牆，沿牆緣找可走點 ──
function avoidWalls(from,to,walls){
  if(!inWall(to,walls))return to;
  // 嘗試 8 方向偏移繞過
  for(let r=3;r<=12;r+=3){for(let a=0;a<8;a++){const ang=a*Math.PI/4;const cand={x:to.x+Math.cos(ang)*r,y:to.y+Math.sin(ang)*r};if(!inWall(cand,walls)&&cand.x>2&&cand.x<98&&cand.y>2&&cand.y<98)return cand;}}
  return from;
}
// ── 射線遮蔽：兩點間視線是否被牆擋住 ──
function lineBlocked(a,b,walls){
  const steps=Math.ceil(dist(a,b)/2);
  for(let i=1;i<steps;i++){const t=i/steps;const p={x:lerp(a.x,b.x,t),y:lerp(a.y,b.y,t)};for(const w of walls){if(p.x>=w.x&&p.x<=w.x+w.w&&p.y>=w.y&&p.y<=w.y+w.h)return true;}}
  return false;
}

