  const filteredTx=useMemo(()=>txFilter==="all"?TX:TX.filter(t=>t.type===txFilter),[txFilter]);
  const TABS=[{id:"overview",label:"總覽"},{id:"analysis",label:"分析"},{id:"budget",label:"預算"}];
