                  {["all","income","expense"].map(f=>{const a=txFilter===f;const c=f==="income"?T.green:f==="expense"?T.red:T.gray;return(<button key={f} onClick={()=>setTxFilter(f)} style={{padding:"2px 7px",borderRadius:99,border:`1px solid ${a?c:T.border}`,background:a?`${c}12`:T.c1,color:a?c:T.gray3,fontSize:8.5,fontWeight:700,cursor:"pointer"}}>{f==="all"?"全部":f==="income"?"收入":"支出"}</button>);})}
