// ── Win rate bar sub-component ────────────────────────────────
function WinRateBar({ wins, losses }) {
  const [w, setW] = useState(0);
  const pct = Math.round((wins / (wins + losses)) * 100);
  useEffect(() => { const t = setTimeout(() => setW(pct), 700); return () => clearTimeout(t); }, [pct]);
  return (
    <div style={{ marginTop:6, height:3, borderRadius:99, background:"rgba(255,255,255,0.07)", overflow:"hidden" }}>
      <div style={{
        height:"100%", width:`${w}%`, borderRadius:99,
        background:"linear-gradient(90deg,#059669,#34d399)",
        boxShadow:"0 0 6px rgba(52,211,153,0.4)",
        transition:"width 1.2s cubic-bezier(.4,0,.2,1) 0.4s",
      }}/>
    </div>
  );
}
return __MasteryModuleInner;
