function FeedItem({ item, index }) {
  const [show, setShow] = useState(false);
  useEffect(() => { const t = setTimeout(() => setShow(true), index * 60); return () => clearTimeout(t); }, []);

  return (
    <div style={{
      opacity:show?1:0, transform:show?"translateX(0)":"translateX(-8px)",
      transition:`opacity .3s ease ${index*0.04}s, transform .3s cubic-bezier(.23,1,.32,1) ${index*0.04}s`,
      marginBottom:10,
    }}>
      <div style={{ display:"flex", gap:8, alignItems:"flex-start" }}>
        {/* Timestamp */}
        <span style={{ color:"#52525b", fontSize:"9px", fontWeight:700, fontFamily:"'Courier New',monospace", flexShrink:0, paddingTop:2, width:32, textAlign:"right" }}>{item.ts}</span>

        {/* Vertical line */}
        <div style={{ width:1.5, background:"rgba(255,255,255,0.05)", flexShrink:0, alignSelf:"stretch", marginTop:4, borderRadius:99 }}/>

        {/* Content */}
        <div style={{ flex:1, minWidth:0 }}>
          {/* Chat */}
          {item.type === "chat" && (
            <div style={{ display:"flex", alignItems:"center", gap:5, flexWrap:"wrap" }}>
              <Volume2 size={10} style={{ color:"#71717a", flexShrink:0 }}/>
              <HeroAvatar initials={item.hero.initials} bg={item.hero.bg} size={18} radius={4}/>
              <span style={{ color: item.team==="藍方" ? BLUE : RED, fontSize:"10px", fontWeight:800 }}>{item.speaker}:</span>
              <span style={{ color:"#d4d4d8", fontSize:"10px" }}>{item.text}</span>
            </div>
          )}

          {/* Caster */}
          {item.type === "caster" && (
            <div style={{ display:"flex", alignItems:"flex-start", gap:5 }}>
              <Tv size={10} style={{ color:"#71717a", flexShrink:0, marginTop:2 }}/>
              <span style={{ color:"#71717a", fontSize:"10px", fontWeight:700, flexShrink:0 }}>賽評：</span>
              <span style={{ fontSize:"10px", lineHeight:1.5 }}><RichText parts={item.text}/></span>
            </div>
          )}

          {/* Event */}
          {item.type === "event" && (
            <>
              <div style={{ display:"flex", alignItems:"flex-start", gap:5, marginBottom:6 }}>
                <Tv size={10} style={{ color:"#71717a", flexShrink:0, marginTop:2 }}/>
                <span style={{ fontSize:"10px", lineHeight:1.5 }}><RichText parts={item.casterText}/></span>
              </div>
              {/* Event card */}
              <div style={{
                borderRadius:10, padding:"8px 10px",
                background:"rgba(24,20,32,0.9)",
                border:`1px solid ${item.card.killerTeam==="藍方" ? `${BLUE}30` : `${RED}30`}`,
                boxShadow:`0 2px 12px rgba(0,0,0,0.4), inset 0 1px 0 rgba(255,255,255,0.04)`,
                display:"flex", alignItems:"center", gap:8,
              }}>
                {/* Assisters */}
                <div style={{ display:"flex", gap:3 }}>
                  {item.card.assisters.map((a,i)=>(
                    <HeroAvatar key={i} initials={a.initials} bg={a.bg} size={26} radius={6}/>
                  ))}
                  <HeroAvatar initials={item.card.killer.initials} bg={item.card.killer.bg} size={26} radius={6}/>
                </div>

                {/* Crossed swords */}
                <div style={{ display:"flex", flexDirection:"column", alignItems:"center", gap:1, flexShrink:0 }}>
                  <Swords size={14} style={{ color: item.card.killerTeam==="藍方" ? BLUE : RED, filter:`drop-shadow(0 0 4px ${item.card.killerTeam==="藍方" ? BLUE : RED}88)` }}/>
                  <span style={{ fontSize:"7px", color:"#52525b", fontWeight:600, letterSpacing:"0.06em" }}>
                    {item.card.type==="kill" ? "擊殺" : "目標"}
                  </span>
                </div>

                {/* Victim */}
                <div style={{ display:"flex", alignItems:"center", gap:4 }}>
                  {item.card.victim.isNeutral && <Flag size={9} style={{ color:GOLD }}/>}
                  <HeroAvatar initials={item.card.victim.initials} bg={item.card.victim.bg} size={26} radius={6}/>
                  <span style={{ color:"#71717a", fontSize:"9px", fontWeight:600 }}>{item.card.victim.label}</span>
                </div>
              </div>
            </>
          )}
        </div>
      </div>
    </div>
  );
}

function PlayByPlayFeed() {
  const endRef = useRef();
  useEffect(() => { endRef.current?.scrollIntoView({ behavior:"smooth" }); }, []);
  return (
    <div style={{ padding:"12px 12px 0" }}>
      {FEED.map((item,i) => <FeedItem key={i} item={item} index={i}/>)}
      <div ref={endRef}/>
    </div>
  );
}

