function MatchupRow({ row }) {
  const { blue:b, red:r, goldDiff, goldFavor, lane } = row;
  const cellStyle = { display:"flex", alignItems:"center" };

  return (
    <div style={{ display:"flex", alignItems:"center", padding:"4px 8px", borderBottom:"1px solid rgba(255,255,255,0.04)", gap:4 }}>
      {/* Lane label */}
      <span style={{ color:"#3f3f46", fontSize:"8px", fontWeight:700, width:20, textAlign:"center", letterSpacing:"0.06em", flexShrink:0 }}>{lane}</span>

      {/* ── BLUE side ── */}
      <div style={{ flex:1, display:"flex", alignItems:"center", gap:3, justifyContent:"flex-start", minWidth:0 }}>
        {/* Avatar + bars */}
        <div style={{ display:"flex", alignItems:"center", gap:1.5, flexShrink:0 }}>
          <StatBars hp={b.hp} mp={b.mp} side="left"/>
          <HeroAvatar initials={b.initials} bg={b.bg} size={28} radius={6} level={b.level} levelPos="br"/>
        </div>
        {/* Spells */}
        <div style={{ display:"flex", flexDirection:"column", gap:1, flexShrink:0 }}>
          {b.spells.map((s,i)=><SpellSquare key={i} label={s.l} color={s.c}/>)}
        </div>
        {/* ID + KDA */}
        <div style={{ minWidth:0 }}>
          <div style={{ color:BLUE, fontSize:"8.5px", fontWeight:800, overflow:"hidden", textOverflow:"ellipsis", whiteSpace:"nowrap", maxWidth:52 }}>{b.id}</div>
          <div style={{ color:"#71717a", fontSize:"8px", fontFamily:"'Courier New',monospace" }}>{b.kda}</div>
        </div>
        {/* CS */}
        <span style={{ color:GOLD, fontSize:"9px", fontWeight:800, marginLeft:"auto", flexShrink:0 }}>{b.cs}</span>
      </div>

      {/* ── Gold diff ── */}
      <div style={{ display:"flex", flexDirection:"column", alignItems:"center", flexShrink:0, width:36 }}>
        {goldDiff > 0 ? (
          <>
            <div style={{ display:"flex", alignItems:"center", gap:1 }}>
              {goldFavor==="藍方" && <ArrowLeft size={8} style={{ color:BLUE }}/>}
              <span style={{ color: goldFavor==="藍方" ? BLUE : goldFavor==="red" ? RED : "#52525b", fontSize:"8px", fontWeight:800 }}>{goldDiff}</span>
              {goldFavor==="red" && <ArrowRight size={8} style={{ color:RED }}/>}
            </div>
            <span style={{ color:"#3f3f46", fontSize:"7px", letterSpacing:"0.04em" }}>金幣差</span>
          </>
        ) : (
          <span style={{ color:"#3f3f46", fontSize:"8px" }}>—</span>
        )}
      </div>

      {/* ── RED side (mirrored) ── */}
      <div style={{ flex:1, display:"flex", alignItems:"center", gap:3, justifyContent:"flex-end", minWidth:0 }}>
        {/* CS */}
        <span style={{ color:GOLD, fontSize:"9px", fontWeight:800, marginRight:"auto", flexShrink:0 }}>{r.cs}</span>
        {/* ID + KDA */}
        <div style={{ minWidth:0, textAlign:"right" }}>
          <div style={{ color:RED, fontSize:"8.5px", fontWeight:800, overflow:"hidden", textOverflow:"ellipsis", whiteSpace:"nowrap", maxWidth:52 }}>{r.id}</div>
          <div style={{ color:"#71717a", fontSize:"8px", fontFamily:"'Courier New',monospace", textAlign:"right" }}>{r.kda}</div>
        </div>
        {/* Spells */}
        <div style={{ display:"flex", flexDirection:"column", gap:1, flexShrink:0 }}>
          {r.spells.map((s,i)=><SpellSquare key={i} label={s.l} color={s.c}/>)}
        </div>
        {/* Avatar + bars */}
        <div style={{ display:"flex", alignItems:"center", gap:1.5, flexShrink:0 }}>
          <HeroAvatar initials={r.initials} bg={r.bg} size={28} radius={6} level={r.level} levelPos="bl"/>
          <StatBars hp={r.hp} mp={r.mp} side="right"/>
        </div>
      </div>
    </div>
  );
}

function TenManPanel() {
  return (
    <div style={{
      flexShrink:0,
      background:"rgba(10,9,12,0.94)",
      backdropFilter:"blur(12px)",
      borderTop:"1px solid rgba(255,255,255,0.08)",
      boxShadow:"0 -8px 32px rgba(0,0,0,0.7)",
    }}>
      {/* Panel header */}
      <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between", padding:"5px 12px 3px" }}>
        <span style={{ color:"#3f3f46", fontSize:"8.5px", fontWeight:700, letterSpacing:"0.12em", textTransform:"uppercase" }}>選手狀態</span>
        <div style={{ display:"flex", gap:10 }}>
          <div style={{ display:"flex", alignItems:"center", gap:3 }}>
            <div style={{ width:8, height:8, borderRadius:2, background:`${BLUE}44`, border:`1px solid ${BLUE}66` }}/>
            <span style={{ color:"#52525b", fontSize:"8px" }}>拉里奧薩</span>
          </div>
          <div style={{ display:"flex", alignItems:"center", gap:3 }}>
            <div style={{ width:8, height:8, borderRadius:2, background:`${RED}44`, border:`1px solid ${RED}66` }}/>
            <span style={{ color:"#52525b", fontSize:"8px" }}>德國海豹</span>
          </div>
        </div>
      </div>
      {MATCHUP_ROWS.map((row,i) => <MatchupRow key={i} row={row}/>)}
      {/* Bottom safe area */}
      <div style={{ height:8 }}/>
    </div>
  );
}

